        return new Source("{% extends 'base.html.twig' %}

{% block title %}Tva index{% endblock %}
{% block stylesheets %}
    
{% endblock %}
{% block body %}
    <div class=\"container\">
    <h1>Tva index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                <th>Id</th>
                <th>Nom</th>
                <th>Taux en %</th>
                <th>Statut</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for tva in tvas %}
            <tr>
                <td>{{ tva.id }}</td>
                <td>{{ tva.nom }}</td>
                <td>{{ tva.prixTva }}</td>
                <td>{{ tva.statut ? 'Yes' : 'No' }}</td>
                <td>
                    <a href=\"{{ path('tva_show', {'id': tva.id}) }}\"><button class=\"btn btn-outline-dark\">Voir</button></a>
                    <a href=\"{{ path('tva_edit', {'id': tva.id}) }}\"><button class=\"btn btn-outline-dark\">Edition</button></a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"4\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>

    <a href=\"{{ path('tva_new') }}\">Create new</a>
    </div>
{% endblock %}
", "admin/tva/index.html.twig", "D:\\Github\\Groupe6\\symfony\\projetLunettes\\templates\\admin\\tva\\index.html.twig");
